import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"神恩天狼目","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/3.瞳术/神恩天狼目 .md","filePath":"4.资源分区/3.瞳术/神恩天狼目 .md"}'),p={name:"4.资源分区/3.瞳术/神恩天狼目 .md"};function d(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"神恩天狼目",tabindex:"-1"},[s("神恩天狼目 "),e("a",{class:"header-anchor",href:"#神恩天狼目","aria-label":'Permalink to "神恩天狼目"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),o('<h1 id="神恩天狼目-1" tabindex="-1">神恩天狼目 <a class="header-anchor" href="#神恩天狼目-1" aria-label="Permalink to &quot;神恩天狼目&quot;">​</a></h1><p>神恩天狼目<br> 一次性瞳术<br> 魔幻本质<br> 价格：C+1200<br> 前提：不具有魔力及魔力变体能量池<br> 对勇者的选拔往往倾向于领导力与其个人的身体素质，而往往会忽视其在魔法方面上的素质，所以时常有无魔力的勇者出现。</p><p>为了补充勇者在对抗魔法相关的能力，教会选择对不具有魔力的勇者施加天狼神的祝福。————《勇者选拔章程-其三》</p><p>在强化该瞳术后，你的眼瞳下方将出现一枚亮蓝色十字亮痕。</p><p>【吾眼即为天狼之目】：作为最基本的祝福，你现在能够通过视觉看见灵体、虚体，这可能会令人物看见一些常态下无法接触的其他事物，这是一个【灵感视觉】效果，天狼神是战士的守护神，无畏，进取，正直是其欣赏之品质，如果在强化该瞳术的之后一场影片内你正大光明（不发起偷袭，不以人质威胁，不使用陷阱或者提前使用布置类爆炸物）的进行了2次同级别战斗且胜利，你在该影片结束后获得【天狼之化身】标记，眼瞳下方的亮蓝色十字亮痕变为米字状。</p><p>【神视无藏】：你可以向天狼请求，让天狼神降临于你的眼瞳之中，替你环视周围，这使你具有D级魔幻本质来源的侦测能力，如果你具有【天狼之化身】，则改为C级，同时你现在可以用决心+学识：神学代替洞察-侦察检定进行侦查。</p><p>【天狼顾】：每轮一次，当你受到攻击时，可以呼唤天狼神的一督，这可以令这次攻击重骰，以后者取代先前的结果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
